(function executeRule(current, previous /*null when async*/) {
	// based on the change to this task, check and update the warnings for siblings in orders after this task
	// if any siblings changed, update parent warning flag
	new TaskTemplateHelpers().checkAndTemplateWarnings(current);
})(current, previous);
